package com.mailautomation.service;
import com.mailautomation.domain.EmailModels.*;import org.springframework.stereotype.Service;import java.util.*;
@Service public class AiEmailService { private static final Map<Category,List<String>> TRIGGERS=Map.of(Category.LEGAL,List.of("lawsuit","attorney","solicitor","gdpr","legal notice","regulatory complaint"),Category.PRODUCT_ISSUE,List.of("bug","crash","login","not working"),Category.DELIVERY_ISSUE,List.of("shipment","lost package","tracking"),Category.RETURN_REFUND,List.of("refund","return","exchange"),Category.BILLING,List.of("payment","subscription","invoice","overcharge"));
 public Analysis analyze(String subject,String content){ String text=(subject+" "+content).toLowerCase(Locale.ROOT); Category category=TRIGGERS.entrySet().stream().filter(e->e.getValue().stream().anyMatch(text::contains)).map(Map.Entry::getKey).findFirst().orElse(text.contains("love")?Category.FEEDBACK:Category.GENERAL_ENQUIRY); Sentiment sentiment=text.matches(".*(angry|furious|lawsuit|unacceptable|third time).*" )?Sentiment.ANGRY:text.matches(".*(still|again|delay|frustrated).*" )?Sentiment.FRUSTRATED:text.contains("sad")?Sentiment.SAD:text.matches(".*(thanks|love|great).*" )?Sentiment.HAPPY:Sentiment.NEUTRAL; String intent=text.contains("status")?"Requests status update":text.contains("lawsuit")||text.contains("attorney")?"Threatening escalation":text.contains("vip")?"VIP customer":"Seeking information"; double confidence=category==Category.GENERAL_ENQUIRY?0.82:0.96; return new Analysis(category,sentiment,intent,confidence,generateReply(category,sentiment)); }
 private String generateReply(Category c, Sentiment s){ return "Thanks for reaching out. I understand this is "+s.name().toLowerCase()+". Based on our knowledge base, we will handle your "+c.name().toLowerCase().replace('_',' ')+" request with the right priority and follow up with next steps."; }
 public record Analysis(Category category, Sentiment sentiment, String intent, double confidence, String draftReply){} }
